import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import copy from "copy-to-clipboard";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function EmployeeManagement() {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    id: null,
    prefix: "Mr",
    name: "",
    email: "",
    phone: "",
    rolePermissionId: "",
    status: "Active",
    totalBalance: "",
    commissionPercentage: "",
  });

  const [filters, setFilters] = useState({
    employeeSearch: "",
    status: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const employeesPerPage = 10;

  const [detailsEmployee, setDetailsEmployee] = useState(null);

  const modalRef = useRef(null);
  const detailsModalRef = useRef(null);
  const navigate = useNavigate();

  /* ================= FETCH ================= */
  function fetchEmployees() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/employees", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setEmployees(res.data.data);
        } else {
          toast.error("Failed to fetch employees");
        }
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Error fetching employees")
      )
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchEmployees();
  }, [navigate]);

  /* ================= INPUT CHANGE ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  }

  /* ================= FILTER CHANGE ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1);
  }

  /* ================= ADD ================= */
  function openAddModal() {
    setFormData({
      id: null,
      prefix: "Mr",
      name: "",
      email: "",
      phone: "",
      rolePermissionId: "",
      status: "Active",
      totalBalance: "",
      commissionPercentage: "",
    });

    const modalEl = document.getElementById("employeeModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= EDIT ================= */
  function openEditModal(emp) {
    setFormData(emp);

    const modalEl = document.getElementById("employeeModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= SUBMIT ================= */
  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    const request = formData.id
      ? axios.put(API_BASE_URL + "/employees/" + formData.id, formData, {
          headers: { Authorization: "Bearer " + token },
        })
      : axios.post(API_BASE_URL + "/employees", formData, {
          headers: { Authorization: "Bearer " + token },
        });

    request
      .then(() => {
        toast.success(
          formData.id
            ? "Employee updated successfully"
            : "Employee created successfully"
        );
        fetchEmployees();
        modalRef.current.hide();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Operation failed")
      );
  }

  /* ================= DELETE ================= */
  function handleDelete(id) {
    if (!window.confirm("Are you sure you want to delete this employee?"))
      return;

    const token = Cookies.get("adminToken");

    axios
      .delete(API_BASE_URL + "/employees/" + id, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Employee deleted successfully");
        fetchEmployees();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Delete failed")
      );
  }

  /* ================= FILTERED DATA ================= */
  const filteredEmployees = employees.filter((emp) => {
    const searchMatch = filters.employeeSearch
      ? (emp.name + emp.phone + emp.email + emp.role)
          .toLowerCase()
          .includes(filters.employeeSearch.toLowerCase())
      : true;

    return (
      searchMatch &&
      (filters.status ? emp.status === filters.status : true)
    );
  });

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * employeesPerPage;
  const indexOfFirst = indexOfLast - employeesPerPage;
  const currentEmployees = filteredEmployees.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.ceil(filteredEmployees.length / employeesPerPage);

  /* ================= COPY ================= */
  function handleCopy(text, type) {
    if (copy(text)) toast.success(type + " copied to clipboard");
    else toast.error("Failed to copy " + type);
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      {/* Back */}
      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate("/dashboard")}
          ></i>
        </div>
      </div>

      {/* Header */}
      <div className="row mb-3">
        <div className="col d-flex justify-content-between">
          <h4 className="fw-bold mb-0">Employee Management</h4>
          <button className="btn btn-primary btn-sm" onClick={openAddModal}>
            + Add Employee
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="row g-3 mb-3">
        <div className="col-md-6">
          <input
            type="text"
            name="employeeSearch"
            className="form-control form-control-sm"
            placeholder="Search (Name, Phone, Email, Role)"
            value={filters.employeeSearch}
            onChange={handleFilterChange}
          />
        </div>

        <div className="col-md-6">
          <select
            name="status"
            className="form-select form-select-sm"
            value={filters.status}
            onChange={handleFilterChange}
          >
            <option value="">Status</option>
            <option value="Active">Active</option>
            <option value="Inactive">Inactive</option>
          </select>
        </div>
      </div>

      {/* Applied Filters */}
      {(filters.employeeSearch || filters.status) && (
        <div className="row g-3 mb-3">
          <div className="col-auto">
            <span className="fw-semibold">Filters applied:</span>
          </div>

          {filters.employeeSearch && (
            <div className="col-auto">
              <span className="badge bg-secondary">
                Search: {filters.employeeSearch}
                <i
                  className="fa fa-times ms-1"
                  style={{ cursor: "pointer" }}
                  onClick={() =>
                    setFilters((prev) => ({ ...prev, employeeSearch: "" }))
                  }
                ></i>
              </span>
            </div>
          )}

          {filters.status && (
            <div className="col-auto">
              <span className="badge bg-secondary">
                Status: {filters.status}
                <i
                  className="fa fa-times ms-1"
                  style={{ cursor: "pointer" }}
                  onClick={() =>
                    setFilters((prev) => ({ ...prev, status: "" }))
                  }
                ></i>
              </span>
            </div>
          )}
        </div>
      )}

      {/* Table */}
      <div className="card mb-3">
        <div className="card border-0">
          {loading ? (
            <div className="text-center p-3">Loading...</div>
          ) : (
            <div className="table-responsive rounded">
              <table className="table table-striped table-hover mb-0 small">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Name</th>
                    <th>Contact</th>
                    <th>Role</th>
                    <th>Status</th>
                    <th>Balance</th>
                    <th>Date & Time</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {currentEmployees.map((emp) => (
                    <tr key={emp.id}>
                      <td>{emp.id}</td>
                      <td>{emp.prefix} {emp.name}</td>
                      <td>
                        <i
                          className="fa-solid fa-phone text-success me-2"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleCopy(emp.phone, "Phone")}
                        ></i>
                        <i
                          className="fa-solid fa-envelope text-primary me-2"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleCopy(emp.email, "Email")}
                        ></i>
                        <i
                          className="fa-solid fa-id-card text-secondary"
                          style={{ cursor: "pointer" }}
                          onClick={() => {
                            setDetailsEmployee(emp);
                            const modalEl =
                              document.getElementById("detailsModal");
                            detailsModalRef.current = new Modal(modalEl);
                            detailsModalRef.current.show();
                          }}
                        ></i>
                      </td>
                      <td>{emp.role}</td>
                      <td>{emp.status}</td>
                      <td>{emp.totalBalance}</td>
                      <td>
                        <div className="d-flex flex-column">
                          <small>
                            <span className="fw-semibold text-muted">
                              Created:
                            </span>{" "}
                            {new Date(emp.createdAt).toLocaleString()}
                          </small>
                          <small>
                            <span className="fw-semibold text-muted">
                              Updated:
                            </span>{" "}
                            {new Date(emp.updatedAt).toLocaleString()}
                          </small>
                        </div>
                      </td>
                      <td>
                        <i
                          className="fa-solid fa-pen-to-square text-primary me-3"
                          style={{ cursor: "pointer" }}
                          onClick={() => openEditModal(emp)}
                        ></i>
                        <i
                          className="fa-solid fa-trash text-danger"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleDelete(emp.id)}
                        ></i>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {/* Pagination */}
      <div className="d-flex justify-content-between align-items-center mb-3">
        <div>
          Page {currentPage} of {totalPages} • {filteredEmployees.length} records
        </div>
        <div>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === 1}
            onClick={() => setCurrentPage((p) => p - 1)}
          >
            <i className="fa-solid fa-chevron-left"></i>
          </button>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === totalPages || totalPages === 0}
            onClick={() => setCurrentPage((p) => p + 1)}
          >
            <i className="fa-solid fa-chevron-right"></i>
          </button>
        </div>
      </div>

      {/* Details Modal */}
      <div className="modal fade" id="detailsModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <div className="modal-header">
              <h5 className="modal-title">Employee Details</h5>
              <button type="button" className="btn-close" data-bs-dismiss="modal"></button>
            </div>
            <div className="modal-body">
              {detailsEmployee && (
                <>
                  <p><strong>Phone:</strong> {detailsEmployee.phone}</p>
                  <p><strong>Email:</strong> {detailsEmployee.email}</p>
                  <p><strong>Role:</strong> {detailsEmployee.role}</p>
                  <p><strong>Status:</strong> {detailsEmployee.status}</p>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Add/Edit Modal */}
      <div className="modal fade" id="employeeModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5 className="modal-title">
                  {formData.id ? "Edit Employee" : "Add Employee"}
                </h5>
                <button type="button" className="btn-close" data-bs-dismiss="modal"></button>
              </div>

              <div className="modal-body">
                <div className="mb-3">
                  <label>Prefix</label>
                  <select
                    name="prefix"
                    className="form-select"
                    value={formData.prefix}
                    onChange={handleInputChange}
                  >
                    <option value="Mr">Mr</option>
                    <option value="Mrs">Mrs</option>
                    <option value="Miss">Miss</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label>Name</label>
                  <input
                    type="text"
                    name="name"
                    className="form-control"
                    value={formData.name}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Email</label>
                  <input
                    type="email"
                    name="email"
                    className="form-control"
                    value={formData.email}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Phone</label>
                  <input
                    type="text"
                    name="phone"
                    className="form-control"
                    value={formData.phone}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Status</label>
                  <select
                    name="status"
                    className="form-select"
                    value={formData.status}
                    onChange={handleInputChange}
                  >
                    <option value="Active">Active</option>
                    <option value="Inactive">Inactive</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label>Total Balance</label>
                  <input
                    type="number"
                    name="totalBalance"
                    className="form-control"
                    value={formData.totalBalance}
                    onChange={handleInputChange}
                  />
                </div>

                <div className="mb-3">
                  <label>Commission %</label>
                  <input
                    type="number"
                    name="commissionPercentage"
                    className="form-control"
                    value={formData.commissionPercentage}
                    onChange={handleInputChange}
                  />
                </div>
              </div>

              <div className="modal-footer">
                <button type="submit" className="btn btn-primary">
                  {formData.id ? "Update" : "Create"}
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>

    </div>
  );
}

export default EmployeeManagement;
